1. **Reproducibility**: `new MLContext(seed: 42)`
2. **Data splitting**: Use `TrainTestSplit` with `testFraction: 0.2`
3. **Metrics logging**: Compute and log multiclass classification metrics (MacroAccuracy, LogLoss, etc.)
4. **PredictionEngine pooling**: Use `PredictionEnginePool<TicketInput, TicketPrediction>` — never a singleton PredictionEngine
5. Categories: Billing, Technical, General

## Implementation plan

### 1. Add NuGet packages
Add `Microsoft.ML` (version 4.*) and `Microsoft.Extensions.ML` (for PredictionEnginePool) to the csproj.

### 2. Create `Models/TicketInput.cs`
```csharp
using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}
```

### 3. Create `Models/TicketPrediction.cs`
```csharp
using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedCategory { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}
```

### 4. Create `Services/ModelTrainerService.cs`
This service trains the model at startup and logs evaluation metrics. It should:
- Use `MLContext(seed: 42)`
- Load data from `Data/tickets.csv`
- Use `TrainTestSplit(data, testFraction: 0.2, seed: 42)`
- Build a pipeline: featurize text columns (Subject, Description), concatenate with Priority, map label to key, use `SdcaMaximumEntropy` for multiclass classification, map key back to label
- Evaluate and log MacroAccuracy, MicroAccuracy, LogLoss
- Save the trained model to a file path
- Implement as an `IHostedService` that trains on startup

```csharp
using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainerService : IHostedService
{
    private readonly ILogger<ModelTrainerService> _logger;
    private readonly string _modelPath;
    private readonly string _dataPath;

    public ModelTrainerService(ILogger<ModelTrainerService> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public Task StartAsync(CancellationToken cancellationToken)
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        _logger.LogInformation("Model evaluation metrics:");
        _logger.LogInformation("  MacroAccuracy: {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("  MicroAccuracy: {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("  LogLoss:       {LogLoss:F4}", metrics.LogLoss);

        mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
}
```

### 5. Create `Controllers/PredictController.cs`
```csharp
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class PredictController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;

    public PredictController(PredictionEnginePool<TicketInput, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost]
    public ActionResult<PredictionResult> Predict([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        return Ok(new PredictionResult
        {
            Category = prediction.PredictedCategory,
            Confidence = prediction.Score.Max()
        });
    }
}

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class PredictionResult
{
    public string Category { get; set; } = string.Empty;
    public float Confidence { get; set; }
}
```

### 6. Update `Program.cs`
```csharp
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

builder.Services.AddHostedService<ModelTrainerService>();

var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();
app.MapControllers();
app.Run();
```

