6. public class ModelTrainerService : IHostedService
7. {
8.     private readonly ILogger<ModelTrainerService> _logger;
9.     private readonly string _modelPath;
10.     private readonly string _dataPath;
11. 
12.     public ModelTrainerService(ILogger<ModelTrainerService> logger, IWebHostEnvironment env)
13.     {
14.         _logger = logger;
15.         _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
16.         _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
17.     }
18. 
19.     public Task StartAsync(CancellationToken cancellationToken)
20.     {
21.         var mlContext = new MLContext(seed: 42);
22. 
23.         IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
24.             _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
25. 
26.         var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);
27. 
28.         var pipeline = mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category))
29.             .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
30.             .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
31.             .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
32.             .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
33.             .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
34. 
35.         _logger.LogInformation("Training ticket classification model...");
36.         var model = pipeline.Fit(split.TrainSet);
37. 
38.         var predictions = model.Transform(split.TestSet);
39.         var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");
40. 
41.         _logger.LogInformation("Model evaluation metrics:");
42.         _logger.LogInformation("  MacroAccuracy: {MacroAccuracy:F4}", metrics.MacroAccuracy);
43.         _logger.LogInformation("  MicroAccuracy: {MicroAccuracy:F4}", metrics.MicroAccuracy);
44.         _logger.LogInformation("  LogLoss:       {LogLoss:F4}", metrics.LogLoss);
45. 
46.         mlContext.Model.Save(model, data.Schema, _modelPath);
47.         _logger.LogInformation("Model saved to {Path}", _modelPath);
48. 
49.         return Task.CompletedTask;
50.     }
51. 
